package tests;

import org.testng.annotations.Test;
import org.testng.Assert;
import pageObjects.LoginPage;
import pageObjects.PIMPage;

/**
 * Test Case ID: 2278
 * Title: Verify that system validates mandatory First Name field when left empty
 * Description: Generated by Qentrix
 * Priority: High
 * QENTRIX_REQUIREMENT_SIGNATURE: c93d8a60f77ea392b25a8f93a93e67faf3c2c9e836133f8c43bdd9f121274639
 */
public class EmployeeValidationTest extends BaseTest {

    @Test(priority = 1, description = "[2278] Verify that system validates mandatory First Name field when left empty")
    public void testMandatoryFirstNameValidation() {
        // Step 1: Navigate to url "https://opensource-demo.orangehrmlive.com/web/index.php/auth/login"
        // Expected: Configured application URL should open
        driver.get("https://opensource-demo.orangehrmlive.com/web/index.php/auth/login");
        
        // Step 2: Enter username "Admin" and password "admin123"
        // Expected: Configured credentials should be entered successfully
        LoginPage loginPage = new LoginPage(driver);
        loginPage.login("Admin", "admin123");
        
        // Wait for dashboard to load
        try {
            Thread.sleep(2000);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        
        // Step 3: Leave First Name empty, enter Last Name "Doe" and Employee ID "67890"
        // Expected: Form should have empty First Name field
        PIMPage pimPage = new PIMPage(driver);
        pimPage.navigateToPIM();
        pimPage.clickAddEmployee();
        
        // Leave First Name empty
        pimPage.enterFirstName("");
        pimPage.enterLastName("Doe");
        pimPage.enterEmployeeId("67890");
        
        // Verify First Name is empty
        String firstNameValue = pimPage.getFirstNameValue();
        Assert.assertTrue(firstNameValue == null || firstNameValue.isEmpty(), 
            "First Name field should be empty");
        
        // Step 4: Click Save button
        // Expected: Validation error message should be displayed for required First Name field
        pimPage.clickSaveButton();
        
        // Wait for validation message
        try {
            Thread.sleep(1000);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        
        Assert.assertTrue(pimPage.isRequiredFieldErrorDisplayed(), 
            "Validation error message should be displayed for required First Name field");
    }
}